const TransformControl = ({ label, value, min, max, step, onChange }: { label: string, value: number, min: number, max: number, step: number, onChange: (v: number) => void }) => (
  <div className="flex flex-col gap-1.5 flex-1">
    <div className="flex justify-between px-1">
      <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-tighter">{label}</span>
