            </div>
          </header>
          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="mb-12 flex flex-col gap-6">
                <div className="flex items-center gap-3 text-zinc-400 mb-2">
                  <Filter size={18} className="text-brand" />
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em]">Clientes</h2>
                </div>
                <div className="flex gap-2 flex-wrap">
                  <button onClick={() => setSelectedClientFilter(null)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${!selectedClientFilter ? 'bg-brand text-black border-brand shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>Todos</button>
                  {clients.map(client => (
                    <button key={client} onClick={() => setSelectedClientFilter(client)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedClientFilter === client ? 'bg-brand text-black border-brand shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>{client}</button>
