interface ToolbarState {
  x: number;
  y: number;
  blockIndex: number;
  blockType: string;
  options: any;
}

const FloatingTextToolbar = ({ 
  state, 
  onClose, 
  onUpdate 
}: { 
  state: ToolbarState, 
  onClose: () => void, 
  onUpdate: (updates: { path: (string | number)[], value: any }[]) => void 
}) => {
  const [localFontSize, setLocalFontSize] = useState(state.options?.fontSize || 40);
  const [localSpacing, setLocalSpacing] = useState(state.options?.letterSpacing || 0);
  const [localLineHeight, setLocalLineHeight] = useState(state.options?.lineHeight || 1.2);
  const [localColor, setLocalColor] = useState(state.options?.color || '#ffffff');

  const [pos, setPos] = useState({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const toolbarRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalFontSize(state.options?.fontSize || 40);
    setLocalSpacing(state.options?.letterSpacing || 0);
    setLocalLineHeight(state.options?.lineHeight || 1.2);
    setLocalColor(state.options?.color || '#ffffff');
    setPos({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  }, [state]);

  const onMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragStart.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.stopPropagation();
  };

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      setPos({ x: e.clientX - dragStart.current.x, y: e.clientY - dragStart.current.y });
    };
    const onMouseUp = () => setIsDragging(false);
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [isDragging]);

  const update = (key: string, val: any) => {
    onUpdate([{ path: ['blocks', state.blockIndex, 'options', key], value: val }]);
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (toolbarRef.current && !toolbarRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    const timeout = setTimeout(() => {
      document.addEventListener('mousedown', handleClickOutside);
    }, 100);
    return () => {
      clearTimeout(timeout);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [onClose]);

  return (
    <div 
      ref={toolbarRef}
      className="fixed z-[1000] bg-zinc-900/95 backdrop-blur-xl border border-white/10 rounded-[28px] shadow-2xl p-6 flex flex-col gap-6 w-80 animate-in zoom-in-95 duration-200 floating-toolbar select-none"
      style={{ top: `${pos.y}px`, left: `${pos.x}px` }}
      onClick={(e) => e.stopPropagation()}
    >
      <div 
        className="flex items-center justify-between cursor-move pb-2 border-b border-white/5 -mt-2"
        onMouseDown={onMouseDown}
      >
        <div className="flex items-center gap-2">
           <GripHorizontal size={14} className="text-zinc-600" />
           <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest">{state.blockType} Editor</span>
        </div>
        <button onClick={onClose} className="p-1 hover:bg-white/5 rounded-full text-zinc-500 hover:text-white"><X size={14}/></button>
      </div>

      <div className="grid grid-cols-1 gap-5">
        <div className="flex gap-4 items-end">
          <div className="flex-1 space-y-1">
             <TransformControl label="Font Size" value={localFontSize} min={10} max={400} step={1} onChange={(v) => { setLocalFontSize(v); update('fontSize', v); }} />
          </div>
          <div className="relative w-12 h-12 rounded-xl overflow-hidden border border-white/10 shadow-inner shrink-0">
             <input type="color" value={localColor} onChange={(e) => { setLocalColor(e.target.value); update('color', e.target.value); }} className="absolute inset-[-4px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none" />
          </div>
        </div>

        <div className="flex gap-4">
          <TransformControl label="Letter Spacing" value={localSpacing} min={-20} max={50} step={1} onChange={(v) => { setLocalFontSize(v); update('letterSpacing', v); }} />
          <TransformControl label="Line Height" value={localLineHeight} min={0.5} max={3.0} step={0.05} onChange={(v) => { setLocalLineHeight(v); update('lineHeight', v); }} />
        </div>

        <div className="space-y-1.5">
           <span className="text-[9px] font-bold text-zinc-500 uppercase px-1">Alignment</span>
           <div className="flex bg-black/40 p-1 rounded-xl border border-white/5 gap-1">
              {[
                { id: 'left', icon: AlignLeft },
                { id: 'center', icon: AlignCenter },
                { id: 'right', icon: AlignRight }
              ].map(align => (
                <button 
                  key={align.id} 
                  onClick={() => update('textAlign', align.id)}
                  className={`flex-1 py-2 flex items-center justify-center rounded-lg transition-all ${state.options?.textAlign === align.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}
                >
                  <align.icon size={16} />
                </button>
              ))}
           </div>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
