  });

  const [toolbarState, setToolbarState] = useState<ToolbarState | null>(null);
  const [isDraggingFile, setIsDraggingFile] = useState(false);

  const [showExportModal, setShowExportModal] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [saveFormData, setSaveFormData] = useState({ name: '', client: '' });
  const [selectedSlidesToExport, setSelectedSlidesToExport] = useState<Set<number>>(new Set());

  const [isExporting, setIsExporting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [exportStatus, setExportStatus] = useState('');

  const [templates] = useState<TemplateDefinition[]>(templateRegistry.getAll());

  // Derived variables to resolve "Cannot find name" errors
  const currentSlide = useMemo(() => carousel?.slides[currentIndex], [carousel, currentIndex]);
  const imageConfig = useMemo(() => currentSlide?.image, [currentSlide]);
  const isLocked = isExporting || isSyncing;

  const [editingIconBlock, setEditingIconBlock] = useState<{ block: Block; index: number } | null>(null);
  const [iconInput, setIconInput] = useState('');

  const canvasRef = useRef<HTMLDivElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // Show toast for feedback
  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;

        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });

        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, [currentIndex]);

  const updateGlobalFX = useCallback((key: string, value: any) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        parsed.slides.forEach((slide: any) => {
          if (!slide.options) slide.options = {};
          if (!slide.options.postFX) slide.options.postFX = {};
          slide.options.postFX[key] = value;
        });
        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, []);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => {
    updateSlideProperties([{ path, value }]);
  }, [updateSlideProperties]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      updateSlideProperty(['image', 'url'], reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  const processProjectFile = useCallback((file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        const result = carouselSchema.safeParse(parsed);
        if (result.success) {
          setDslInput(content);
          setCurrentProjectId(null);
          setSaveFormData({ name: `Importado ${new Date().toLocaleDateString()}`, client: 'Importado' });
          setCurrentIndex(0);
          setView('EDITOR');
          showToast("Projeto importado com sucesso!");
        } else {
          showToast("Arquivo JSON inválido.", "error");
        }
      } catch (err) {
        showToast("Falha ao ler o arquivo.", "error");
      }
    };
    reader.readAsText(file);
  }, [setDslInput, setCurrentProjectId, setSaveFormData, setCurrentIndex, setView, showToast]);

  const handleImportProject = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processProjectFile(file);
  };

  const handleGlobalDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleGlobalDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
  };

  const handleGlobalDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
    const file = e.dataTransfer.files?.[0];
    if (file) processProjectFile(file);
  };

  // Paste (CTRL+V) support for images
  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      if (view !== 'EDITOR') return;
      const items = e.clipboardData?.items;
      if (!items) return;
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const blob = items[i].getAsFile();
          if (!blob) continue;
          const reader = new FileReader();
          reader.onload = (event) => {
            const result = event.target?.result as string;
            if (result) {
              if (editingIconBlock) {
                updateSlideProperties([
                  { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: result },
                  { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }
                ]);
                showToast("Ícone personalizado colado!");
              } else {
                updateSlideProperty(['image', 'url'], result);
                showToast("Imagem do slide atualizada!");
              }
            }
          };
          reader.readAsDataURL(blob);
          e.preventDefault();
          break;
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [view, updateSlideProperty, updateSlideProperties, editingIconBlock, showToast]);

  // Load Data: Palettes from Supabase, Projects from Local Storage
  const loadData = useCallback(async () => {
    setIsSyncing(true);
    try {
      // Local Projects
      const localProjects = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      setProjects(localProjects);

      // Palettes from Supabase (Table: brand_palettes)
      const { data, error } = await supabase.from('brand_palettes').select('*');
      if (error) throw error;

      setBrandPresets([...DEFAULT_BRAND_PRESETS, ...(data || [])]);
    } catch (err: any) {
      console.error("Load failed", err);
      showToast("Falha ao sincronizar paletas. Usando locais.", "error");
      const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      setBrandPresets([...DEFAULT_BRAND_PRESETS, ...localPalettes]);
    } finally {
      setIsSyncing(false);
    }
  }, [showToast]);

  useEffect(() => { loadData(); }, [loadData]);

  const currentPalette = brandPresets.find(p => p.id === activePaletteId)?.colors || DEFAULT_BRAND_PRESETS[0].colors;

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) {
        setCarousel(result.data);
        setError(null);
      } else {
        setError(result.error.issues.map(e => `[${e.path.join(' → ')}]: ${e.message}`).join('\n'));
      }
    } catch (e: any) {
      setError(`Sintaxe: ${e.message}`);
    }
  }, [dslInput]);

  useEffect(() => { handleRender(); }, [handleRender]);

  const handleNewProject = () => {
    setDslInput(INITIAL_DSL);
    setCurrentProjectId(null);
    setCurrentIndex(0);
    setSaveFormData({ name: '', client: '' });
    setView('EDITOR');
  };

  const handleOpenProject = (proj: Project) => {
    setDslInput(proj.data);
    setCurrentProjectId(proj.id);
    setSaveFormData({ name: proj.name, client: proj.client_name });
    setCurrentIndex(0);
    setView('EDITOR');
  };

  const saveToLocal = (newProject: any) => {
    const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
    const index = existing.findIndex((p: any) => p.id === newProject.id);
    let updated;
    if (index >= 0) {
      updated = [...existing];
      updated[index] = newProject;
    } else {
      updated = [newProject, ...existing];
    }
    localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updated));
    setProjects(updated);
  };

  const handleSaveProject = async () => {
    if (!saveFormData.name.trim()) return;
    setIsSyncing(true);
    const now = Date.now();
    const localId = currentProjectId || `proj_${now}`;

    const projectObj: Project = {
      id: localId,
      name: saveFormData.name,
      client_name: saveFormData.client || 'Geral',
      data: dslInput,
      slideCount: carousel?.slides.length || 0,
      updatedAt: now
    };

    try {
      saveToLocal(projectObj);
      setCurrentProjectId(localId);
      setShowSaveModal(false);
      showToast("Projeto salvo localmente!");
    } catch (err: any) {
      console.error("Save failed", err);
      showToast("Falha ao salvar.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteProject = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 

    const confirmed = window.confirm("Excluir projeto permanentemente?");
    if (!confirmed) return;

    setIsSyncing(true);
    try {
      const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      const updated = existing.filter((p: any) => p.id !== id);
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updated));
      setProjects(updated);

      if (currentProjectId === id) handleNewProject();
      showToast("Projeto removido.");
    } catch (err: any) {
      console.error("Delete error:", err);
      showToast("Falha ao excluir.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleCanvasMouseUp = (e: React.MouseEvent) => {
    const selection = window.getSelection();
    if (!selection || selection.isCollapsed) return;
    const range = selection.getRangeAt(0);
    const rect = range.getBoundingClientRect();
    const targetBlock = (e.target as HTMLElement).closest('[data-block-index]');
    if (targetBlock) {
       const bIndex = parseInt(targetBlock.getAttribute('data-block-index') || '0', 10);
       const bType = targetBlock.querySelector('[data-block-type]')?.getAttribute('data-block-type') || 'Block';
       const currentBlock = carousel?.slides?.[currentIndex]?.blocks?.[bIndex];
       if (currentBlock) {
          setToolbarState({
            x: Number(rect.left) + Number(rect.width) / 2,
            y: Number(rect.top),
            blockIndex: bIndex,
            blockType: bType,
            options: currentBlock.options || {}
          });
       }
    }
  };

  const startBatchExport = async () => {
    if (!carousel || !canvasRef.current || isExporting || selectedSlidesToExport.size === 0) return;
    setShowExportModal(false);
    const originalIndex = currentIndex;
    const exportIndices = Array.from(selectedSlidesToExport).sort((a, b) => Number(a) - Number(b));
    const images: { name: string; dataUrl: string }[] = [];
    setIsExporting(true);
    try {
      const total = exportIndices.length;
      for (let i = 0; i < total; i++) {
        const slideIdx = exportIndices[i];
        setExportStatus(`Processando: ${i + 1} de ${total}`);
        setExportProgress(Math.round(((i + 1) / total) * 100));
        setCurrentIndex(slideIdx);
        await new Promise(resolve => setTimeout(resolve, 850));
        const dataUrl = await captureJpeg(canvasRef.current);
        images.push({ name: `slide-${(i + 1).toString().padStart(2, '0')}.jpg`, dataUrl });
      }
      setExportStatus('Finalizando ZIP...');
      await downloadZip(images, `carousel-${Date.now()}.zip`, dslInput);
      setExportStatus('Exportação concluída!');
      setTimeout(() => {
        setIsExporting(false);
        setExportProgress(0);
        setCurrentIndex(originalIndex);
      }, 1500);
    } catch (err) {
      setError('Erro na exportação.');
      setIsExporting(false);
      setCurrentIndex(originalIndex);
    }
  };

  const handleApplyPalettePreset = (preset: any) => {
    setActivePaletteId(preset.id);
    const defaults = preset.defaults || {
      bg: preset.colors[0],
      accent: preset.colors[2],
      text: preset.colors[1],
      cardBg: preset.colors[2]
    };
    updateSlideProperties([
      { path: ['options', 'background'], value: defaults.bg },
      { path: ['options', 'accent'], value: defaults.accent },
      { path: ['options', 'text'], value: defaults.text },
      { path: ['options', 'cardBg'], value: defaults.cardBg }
    ]);
  };

  const handleCreatePalette = async () => {
    if (!newPaletteData.name.trim()) return;
    setIsSyncing(true);
    const newId = crypto.randomUUID();

    const newPreset = {
      id: newId,
      name: newPaletteData.name,
      colors: newPaletteData.colors,
      defaults: {
        bg: newPaletteData.colors[0],
        accent: newPaletteData.colors[2],
        text: newPaletteData.colors[1],
        cardBg: newPaletteData.colors[2]
      }
    };

    try {
      const { error: insertError } = await supabase.from('brand_palettes').insert([newPreset]);
      if (insertError) throw insertError;
      showToast("Paleta sincronizada com sucesso!");
    } catch (err: any) {
      console.error("Supabase sync failed, falling back to local storage", err);
      showToast("Erro ao sincronizar. Salvando localmente.", "error");
      const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify([...localPalettes, newPreset]));
    } finally {
      setIsCreatingPalette(false);
      setNewPaletteData({ name: '', colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308'] });
      loadData();
      setIsSyncing(false);
    }
  };

  const handleDeletePalette = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (DEFAULT_BRAND_PRESETS.some(d => d.id === id)) return;
    setIsSyncing(true);
    try {
      const { error } = await supabase.from('brand_palettes').delete().eq('id', id);
      if (error) {
        const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
        const filtered = localPalettes.filter((p: any) => p.id !== id);
        localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify(filtered));
      }
      showToast("Paleta removida.");
      loadData();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleTemplateSelect = (tpl: TemplateDefinition) => {
    const updates: { path: (string | number)[], value: any }[] = [
      { path: ['template'], value: tpl.name }
    ];

    switch(tpl.name) {
      case 'PREMIUM_GLASS':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_GLASS_CARD' });
        updates.push({ path: ['image', 'boxOverlay'], value: 'dark' });
        break;
      case 'SPLIT_EDITORIAL':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_SPLIT_HALF' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        break;
      case 'PROFILE_FOCUS':
        updates.push({ path: ['image', 'type'], value: 'FOCUS_SUBJECT' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        break;
      case 'FOCUS_OBJECT':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        updates.push({ path: ['image', 'width'], value: 600 });
        break;
      case 'CINEMATIC_BG':
      case 'HERO_STATEMENT':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BACKGROUND' });
        updates.push({ path: ['image', 'overlay'], value: 'dark' });
        break;
      case 'IMAGE_SIDEBAR':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        updates.push({ path: ['image', 'width'], value: 400 });
        break;
      case 'CARD_BOX':
      case 'INFO_LIST_V1':
      case 'CARD_CLUSTER':
        if (!imageConfig?.url) {
           updates.push({ path: ['image', 'type'], value: 'NONE' });
        }
        break;
    }

    updateSlideProperties(updates);
    showToast(`Template ${tpl.name.replace(/_/g, ' ')} aplicado!`, "success");
  };

  const clients = useMemo(() => {
    const set = new Set(projects.map(p => p.client_name));
    return Array.from(set).sort();
  }, [projects]);

  const filteredProjects = useMemo(() => {
    return projects.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.client_name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesClient = selectedClientFilter ? p.client_name === selectedClientFilter : true;
      return matchesSearch && matchesClient;
    });
  }, [projects, searchQuery, selectedClientFilter]);

  return (
    <div 
      onDragOver={handleGlobalDragOver}
      onDragLeave={handleGlobalDragLeave}
      onDrop={handleGlobalDrop}
      className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden relative"
    >
      {isDraggingFile && (
        <div className="fixed inset-0 z-[10000] bg-brand/10 backdrop-blur-sm border-4 border-dashed border-brand/50 flex items-center justify-center pointer-events-none">
          <div className="bg-zinc-900 p-10 rounded-[40px] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in-95">
             <Upload size={64} className="text-brand animate-bounce" />
             <p className="text-xl font-black text-white uppercase italic tracking-tighter">Solte o projeto para importar</p>
          </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-[0_30px_90px_rgba(0,0,0,0.6)] backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-brand/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} strokeWidth={3} /> : <AlertCircle size={28} strokeWidth={3} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      <input type="file" ref={importInputRef} onChange={handleImportProject} accept=".json" className="hidden" />

      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />
      )}

      {showExportModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowExportModal(false)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Exportar Carrossel</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">ZIP conterá imagens + arquivo de configuração do projeto</p>
                 </div>
                 <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500 transition-colors"><X size={24}/></button>
              </div>

              <div className="grid grid-cols-4 gap-4 max-h-[400px] overflow-y-auto custom-scrollbar p-1">
                 {carousel?.slides.map((s, idx) => (
                    <button 
                      key={idx}
                      onClick={() => {
                        const next = new Set(selectedSlidesToExport);
                        if (next.has(idx)) next.delete(idx);
                        else next.add(idx);
                        setSelectedSlidesToExport(next);
                      }}
                      className={`relative aspect-[4/5] rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-3 overflow-hidden ${selectedSlidesToExport.has(idx) ? 'border-brand bg-brand/10' : 'border-white/5 bg-black/40 hover:border-white/20'}`}
                    >
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center ${selectedSlidesToExport.has(idx) ? 'bg-brand text-black' : 'bg-zinc-800 text-zinc-500'}`}>
                          <span className="font-black text-xs">{idx + 1}</span>
                       </div>
                       <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest truncate px-2 w-full">{s.template.replace(/_/g, ' ')}</p>
                       {selectedSlidesToExport.has(idx) && (
                         <div className="absolute top-2 right-2 text-brand"><CheckCircle2 size={16} /></div>
                       )}
                    </button>
                 ))}
              </div>

              <div className="flex gap-4 pt-4 border-t border-white/5">
                 <button onClick={() => setSelectedSlidesToExport(new Set())} className="px-6 py-5 text-[10px] font-black text-zinc-500 uppercase tracking-widest hover:text-white transition-all">Limpar Tudo</button>
                 <button onClick={() => setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i)))} className="px-6 py-5 text-[10px] font-black text-brand uppercase tracking-widest hover:text-brand/80 transition-all">Selecionar Todos</button>
                 <button onClick={startBatchExport} disabled={selectedSlidesToExport.size === 0} className="flex-1 py-5 bg-brand hover:bg-brand/80 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3">
                    <Download size={18} strokeWidth={3} /> Gerar {selectedSlidesToExport.size} Slides
                 </button>
              </div>
           </div>
        </div>
      )}

      {editingIconBlock && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setEditingIconBlock(null)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Escolher Ícone</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Biblioteca de símbolos ou cole PNG via CTRL+V</p>
                 </div>
                 <button onClick={() => setEditingIconBlock(null)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>

              <div className="p-6 border-2 border-dashed border-brand/20 bg-brand/5 rounded-[24px] flex flex-col items-center justify-center gap-2 group hover:border-brand/50 transition-all">
                <ClipboardPaste size={32} className="text-brand opacity-60 group-hover:opacity-100" />
                <p className="text-[10px] font-black uppercase text-brand/80 tracking-widest">Dica: Cole um PNG/JPG diretamente aqui (CTRL+V)</p>
              </div>

              <div className="grid grid-cols-4 sm:grid-cols-6 gap-4 p-1">
                 {ICON_LIBRARY_PRESETS.map(item => (
                    <button 
                      key={item.id}
                      onClick={() => {
                        updateSlideProperties([
                          { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: item.id },
                          { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: undefined }
                        ]);
                        setEditingIconBlock(null);
                      }}
                      className={`flex flex-col items-center justify-center gap-3 p-5 rounded-3xl border-2 transition-all group ${editingIconBlock.block.options?.icon === item.id ? 'border-brand bg-brand/10 text-brand' : 'border-white/5 bg-black/40 hover:border-brand/50'}`}
                    >
                       <item.icon size={32} strokeWidth={1.5} className="transition-transform group-hover:scale-110" />
                       <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-600 group-hover:text-brand">{item.label}</span>
                    </button>
                 ))}
              </div>

              <div className="space-y-3">
                 <label className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Personalizado (Lucide Name, URL ou SVG)</label>
                 <div className="flex gap-3">
                    <input type="text" placeholder="Ex: Rocket, https://..., <svg..." className="flex-1 bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm font-bold text-white outline-none focus:border-brand/50 transition-all" value={iconInput} onChange={(e) => setIconInput(e.target.value)} />
                    <button onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: iconInput }, { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }]); setEditingIconBlock(null); }} className="px-8 py-4 bg-zinc-800 text-white font-black uppercase text-[10px] rounded-2xl hover:bg-zinc-700 transition-all">Aplicar</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {isCreatingPalette && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setIsCreatingPalette(false)}>
           <div className="w-full max-w-xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Nova Identidade Visual</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Defina as cores da marca</p>
                 </div>
                 <button onClick={() => setIsCreatingPalette(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="space-y-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Nome da Paleta / Marca</label>
                  <input type="text" value={newPaletteData.name} onChange={(e) => setNewPaletteData({ ...newPaletteData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-5 px-6 text-base text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Ex: Apple Minimal" />
                </div>
                <div className="grid grid-cols-5 gap-4">
                   {['Fundo', 'Texto', 'Acento', 'Destaque', 'Cards'].map((label, idx) => (
                     <div key={idx} className="flex flex-col items-center gap-3">
                        <span className="text-[9px] font-black uppercase text-zinc-600 tracking-tighter">{label}</span>
                        <div className="relative w-16 h-16 rounded-full overflow-hidden border-2 border-white/10 shadow-2xl group cursor-pointer ring-offset-4 ring-offset-zinc-900 focus-within:ring-2 ring-brand transition-all">
                           <input type="color" value={newPaletteData.colors[idx]} onChange={(e) => { const nextColors = [...newPaletteData.colors]; nextColors[idx] = e.target.value; setNewPaletteData({ ...newPaletteData, colors: nextColors }); }} className="absolute inset-[-10px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none bg-transparent" />
                           <div className="absolute inset-0 pointer-events-none flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/20 transition-opacity"><Pipette size={16} className="text-white" /></div>
                        </div>
                     </div>
                   ))}
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                 <button onClick={() => setIsCreatingPalette(false)} className="flex-1 py-5 text-[11px] font-black text-zinc-500 uppercase tracking-widest hover:text-white transition-all">Cancelar</button>
                 <button onClick={handleCreatePalette} disabled={!newPaletteData.name.trim()} className="flex-[2] py-5 bg-brand hover:bg-brand/80 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-2xl transition-all">Criar Paleta Agora</button>
              </div>
           </div>
        </div>
      )}

      {isExporting && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center bg-black/80 backdrop-blur-3xl animate-in fade-in">
           <div className="w-full max-w-md space-y-10 text-center px-10">
              <div className="relative inline-block">
                 <div className="absolute inset-0 blur-3xl bg-brand/20 animate-pulse rounded-full" />
                 <Loader2 size={64} className="animate-spin text-brand relative mx-auto" strokeWidth={3} />
              </div>
              <div className="space-y-4">
                 <h2 className="text-2xl font-black text-white uppercase italic tracking-tighter animate-pulse">{exportStatus}</h2>
                 <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-brand transition-all duration-500" style={{ width: `${exportProgress}%` }} />
                 </div>
                 <p className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.3em]">{exportProgress}% COMPLETO</p>
              </div>
           </div>
        </div>
      )}

      {showSaveModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowSaveModal(false)}>
           <div className="w-full max-w-md bg-zinc-900 border border-white/10 rounded-[32px] p-8 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <h2 className="text-lg font-black text-white uppercase tracking-tight">Salvar Projeto</h2>
                 <button onClick={() => setShowSaveModal(false)} className="p-2 hover:bg-white/5 rounded-full transition-colors"><X size={24}/></button>
              </div>
              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Nome do Projeto</label>
                  <input type="text" value={saveFormData.name} onChange={(e) => setSaveFormData({ ...saveFormData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Ex: Campanha Verão" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Cliente</label>
                  <input type="text" list="client-datalist" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Ex: Impact" />
                  <datalist id="client-datalist">{clients.map(c => <option key={c} value={c} />)}</datalist>
                </div>
              </div>
              <button type="button" onClick={handleSaveProject} disabled={isSyncing || !saveFormData.name.trim()} className="w-full py-5 bg-brand text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3 disabled:opacity-30 transition-all active:scale-95">
                {isSyncing ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                {isSyncing ? "Salvando..." : (currentProjectId ? "Atualizar Projeto" : "Salvar Projeto")}
              </button>
           </div>
        </div>
      )}

      {view === 'DASHBOARD' ? (
        <div className="min-h-screen w-full bg-[#050507] text-white flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/80 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
              <img src={LOGO_URL} className="h-16 object-contain" alt="Logo" />
              <div className="flex items-center gap-2 px-3 py-1 bg-zinc-800 rounded-lg text-[9px] font-black uppercase text-zinc-500">
                <DatabaseZap size={10} className="text-brand" /> Supabase Sync
              </div>
            </div>
            <div className="flex-1 max-w-xl mx-20 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} />
              <input type="text" placeholder="Pesquisar projetos..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-[13px] font-bold text-white outline-none focus:border-brand/50 transition-all" />
            </div>
            <div className="flex gap-4">
              <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 px-6 py-3 bg-white/5 border border-white/10 text-white font-black uppercase text-[11px] rounded-xl hover:bg-white/10 transition-all shadow-xl active:scale-95">
                <Upload size={16} /> Subir Projeto
              </button>
              <button onClick={handleNewProject} className="flex items-center gap-2 px-6 py-3 bg-brand text-black font-black uppercase text-[11px] rounded-xl hover:bg-brand/80 transition-all shadow-xl shadow-brand/10 active:scale-95"><Plus size={16} strokeWidth={3} /> Criar Projeto</button>
            </div>
          </header>
          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="mb-12 flex flex-col gap-6">
                <div className="flex items-center gap-3 text-zinc-400 mb-2">
                  <Filter size={18} className="text-brand" />
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em]">Clientes</h2>
                </div>
                <div className="flex gap-2 flex-wrap">
                  <button onClick={() => setSelectedClientFilter(null)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${!selectedClientFilter ? 'bg-brand text-black border-brand shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>Todos</button>
                  {clients.map(client => (
                    <button key={client} onClick={() => setSelectedClientFilter(client)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedClientFilter === client ? 'bg-brand text-black border-brand shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>{client}</button>
                  ))}
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProjects.map(proj => (
                  <div key={proj.id} className={`h-80 bg-zinc-900/40 border border-white/5 rounded-[32px] p-0 flex flex-col transition-all cursor-pointer group overflow-hidden ${currentProjectId === proj.id ? 'ring-2 ring-brand/50' : ''}`}>
                      <div onClick={() => handleOpenProject(proj)} className="flex-1 p-8 space-y-4 hover:bg-white/5 transition-colors">
                        <div className="flex items-start justify-between"><div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5 group-hover:border-brand/20"><Library size={20} className="text-zinc-600 group-hover:text-brand" /></div></div>
                        <div className="space-y-3 pointer-events-none">
                          <div className="space-y-1">
                            <div className="flex items-center gap-1.5 text-brand mb-1 font-black uppercase tracking-widest text-[9px]"><UserCircle size={10} />{proj.client_name}</div>
                            <h3 className="text-base font-black text-white truncate">{proj.name}</h3>
                          </div>
                          <div className="flex flex-col gap-1.5 opacity-50">
                              <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Layers size={10} /> {proj.slideCount} Slides</div>
                              <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Clock size={10} /> {new Date(proj.updatedAt).toLocaleDateString()}</div>
                          </div>
                        </div>
