                <div className="grid grid-cols-1 gap-2.5 animate-in fade-in duration-300">
                   {templates.map(tpl => (
                      <button key={tpl.name} onClick={() => handleTemplateSelect(tpl)} className={`w-full p-4 text-left border rounded-xl transition-all flex items-center justify-between group ${currentSlide?.template === tpl.name ? 'border-brand bg-brand/10 shadow-[0_0_20px_rgba(31,178,247,0.1)]' : 'border-white/5 bg-white/5 hover:border-brand/20'}`}>
                        <div className="flex items-center gap-4"><div className={`w-12 h-12 rounded-xl flex items-center justify-center border transition-all ${currentSlide?.template === tpl.name ? 'bg-brand border-brand shadow-[0_0_20px_rgba(31,178,247,0.3)]' : 'bg-black border-white/5 group-hover:border-white/20'}`}><Library size={20} className={currentSlide?.template === tpl.name ? 'text-black' : 'text-zinc-500'} /></div><div><p className={`text-[10px] font-black uppercase mb-0.5 tracking-tighter ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[9px] text-zinc-500 opacity-60 font-medium">{tpl.description}</p></div></div>
                        {currentSlide?.template === tpl.name && <Check className="text-brand" size={16} />}
                      </button>
                    ))}
                </div>
              ) : activeTab === 'ASSETS' ? (
                <div className="space-y-8 animate-in fade-in duration-300">
                  <div className={`p-6 border rounded-[32px] transition-all ${isLocked ? 'opacity-50 pointer-events-none' : 'bg-white/5 border-white/10'}`}>
                    {imageConfig?.url ? (
                      <div className="space-y-10">
                        <div className="relative aspect-video rounded-2xl overflow-hidden bg-zinc-950 border border-white/5 group shadow-inner"><img src={imageConfig.url} className="w-full h-full object-contain" /><div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"><button onClick={() => updateSlideProperty(['image', 'url'], undefined)} className="p-3 bg-red-500 text-white rounded-xl shadow-xl hover:scale-110 transition-transform"><Trash2 size={20}/></button></div></div>
                        <div className="space-y-4">
                           <span className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Layout de Imagem</span>
                           <div className="grid grid-cols-5 gap-2">{IMAGE_TYPE_PRESETS.map(preset => (<button key={preset.id} onClick={() => updateSlideProperty(['image', 'type'], preset.id)} className={`flex flex-col items-center gap-2 p-2 rounded-xl border transition-all ${imageConfig.type === preset.id ? 'bg-brand border-brand text-black shadow-lg' : 'bg-black/40 border-white/5 text-zinc-500 hover:text-white'}`} title={preset.label}><preset.icon size={16} /></button>))}</div>
                        </div>
                        <div className="space-y-6">
                          <div className="flex gap-4"><TransformControl label="Escala" value={imageConfig.scale ?? 1} min={0.1} max={5} step={0.05} onChange={(v) => updateSlideProperty(['image', 'scale'], v)} />{imageConfig.type === 'IMAGE_BOX' && <TransformControl label="Largura Box" value={imageConfig.width ?? 480} min={200} max={1000} step={10} onChange={(v) => updateSlideProperty(['image', 'width'], v)} />}</div>
                          <div className="flex gap-4"><TransformControl label="Offset X" value={imageConfig.x ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'x'], v)} /><TransformControl label="Offset Y" value={imageConfig.y ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'y'], v)} /></div>
                          <TransformControl label="Opacidade do Fundo" value={imageConfig.backgroundOpacity ?? 1} min={0} max={1} step={0.05} onChange={(v) => updateSlideProperty(['image', 'backgroundOpacity'], v)} />
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center h-48 border-2 border-dashed border-white/5 rounded-[40px] hover:bg-white/5 transition-all relative group cursor-pointer"><PlusCircle className="w-10 h-10 text-zinc-800 mb-4 group-hover:text-brand transition-colors" /><p className="text-[10px] font-black uppercase text-zinc-600 group-hover:text-zinc-400">Arraste ou clique para Upload</p><input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleImageUpload} disabled={isLocked} /></div>
                    )}
                  </div>
                  <div className="px-1 py-4 bg-zinc-800/20 border border-zinc-700/30 rounded-2xl flex flex-col items-center gap-3"><ClipboardPaste size={20} className="text-zinc-600" /><p className="text-[10px] font-black uppercase text-zinc-500 text-center px-4">Use CTRL+V no editor para colar imagens rapidamente!</p></div>
                </div>
              ) : activeTab === 'JSON' ? (
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-2">
                    <button onClick={() => importInputRef.current?.click()} className="flex items-center justify-center gap-2 py-3 bg-white/5 border border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest text-white hover:bg-white/10 transition-all"><Upload size={14} /> Subir JSON</button>
                    <button onClick={() => { const blob = new Blob([dslInput], { type: 'application/json' }); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `projeto-${Date.now()}.json`; a.click(); URL.revokeObjectURL(url); }} className="flex items-center justify-center gap-2 py-3 bg-white/5 border border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest text-white hover:bg-white/10 transition-all"><Download size={14} /> Baixar JSON</button>
                  </div>
                  <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[500px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-xl outline-none custom-scrollbar" spellCheck={false} />
                </div>
              ) : null}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950 flex gap-3"><button disabled={!carousel || isExporting} onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="flex-1 py-4 bg-brand hover:bg-brand/80 disabled:opacity-30 text-black font-black rounded-xl text-[10px] uppercase transition-all shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar</button></footer>
          </aside>
          <main className="flex-1 bg-[#18181b] relative flex flex-col">
            {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4 duration-300"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}
            <div className="absolute top-5 right-5 z-40 flex items-center gap-0.5 bg-black/30 backdrop-blur-xl p-1 rounded-xl border border-white/5 opacity-60 hover:opacity-100 transition-opacity"><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomOut size={16} /></button><div className="px-2 text-[9px] font-black font-mono text-zinc-400 w-10 text-center">{(zoom * 100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomIn size={16} /></button></div>
            <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar p-10" onMouseUp={handleCanvasMouseUp}><div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">{carousel?.slides?.[currentIndex] ? <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(block, blockIdx) => setEditingIconBlock({ block, index: blockIdx })} /> : <div className="opacity-10"><Loader2 className="w-10 h-10 animate-spin text-brand" /></div>}</div></div>
            {carousel && carousel.slides.length > 0 && (<div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-8 bg-black/40 backdrop-blur-xl px-8 py-4 rounded-[32px] border border-white/5 shadow-2xl transition-opacity hover:opacity-100 opacity-90"><button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20} strokeWidth={3}/></button><div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-brand shadow-lg shadow-brand/30' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div><button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20} strokeWidth={3}/></button></div>)}
          </main>
        </div>
      )}
    </div>
  );
};

export default App;
